@layer components {
  .shine-effect {
    --shine-repeat: infinite;

    @apply relative inline-block overflow-hidden;
  }

  .shine-effect::after {
    content: '';
    position: absolute;
    top: 0;
    left: -50%;
    width: 40px;
    height: 100%;
    background: linear-gradient(
      90deg,
      transparent,
      rgba(255, 255, 255, 0.6),
      transparent
    );
    transform: skewX(-20deg);
    animation: shine-sweep 4s linear; /* Increased to 4s total */
    animation-delay: var(--shine-delay, 0s);
    animation-iteration-count: var(--shine-repeat);
    animation-fill-mode: forwards;
  }

  @keyframes shine-sweep {
    /* First 60%: pause */
    0%,
    60% {
      left: -50%;
      opacity: 0;
    }
    /* Shine effect happens in the last 40% */
    60.01% {
      opacity: 1;
    }
    95% {
      opacity: 1;
    }
    100% {
      left: 150%;
      opacity: 0;
    }
  }
}
