```tsx web/breeze/components/Discounts/ShineText.tsx
import { useIntersectionObserver } from '@otovo/shared/hooks/useIntersectionObserver';
import { useEffect, useState } from 'react';

interface ShineTextProps {
  children: React.ReactNode;
  className?: string;
  iterations?: number;
  delay?: string;
}

export const ShineText = ({
  children,
  className = '',
  iterations = 6,
  delay = 0,
}: ShineTextProps) => {
  const [ref, isInViewPort] = useIntersectionObserver<HTMLSpanElement>();
  const [shouldAnimate, setShouldAnimate] = useState(false);

  useEffect(() => {
    if (isInViewPort) {
      setShouldAnimate(true);
    }
  }, [isInViewPort]);

  return (
    <span
      ref={ref}
      className={`shine-effect ${className}`}
      style={
        {
          '--shine-repeat': shouldAnimate ? iterations : 0,
          '--shine-delay': delay,
        } as React.CSSProperties
      }
    >
      {children}
    </span>
  );
};
```



Do you know of any way of making the keyframes constant speed? regardless of size of the element I'm wrapping in ShineText?

Yes! To make the shine effect move at a constant speed regardless of element size, you can modify the animation to use CSS `translate` with viewport units (vw) instead of using `left` percentages. This way, the shine will travel at a consistent speed across the screen regardless of the element's width.

Here's how you can modify the CSS:

```css
.shine-effect::after {
  content: '';
  position: absolute;
  top: 0;
  left: 0; /* Changed from -50% */
  width: 40px;
  height: 100%;
  background: linear-gradient(
    90deg,
    transparent,
    rgba(255, 255, 255, 0.6),
    transparent
  );
  transform: skewX(-20deg) translateX(-100vw); /* Added translateX */
  animation: shine-sweep 4s linear;
  animation-delay: var(--shine-delay, 0s);
  animation-iteration-count: var(--shine-repeat);
  animation-fill-mode: forwards;
}

@keyframes shine-sweep {
  0%,
  60% {
    transform: skewX(-20deg) translateX(-100vw);
    opacity: 0;
  }
  60.01% {
    opacity: 1;
  }
  95% {
    opacity: 1;
  }
  100% {
    transform: skewX(-20deg) translateX(100vw);
    opacity: 0;
  }
}
```

This approach:
1. Uses `translateX` with viewport units (vw) instead of `left` percentages
2. Makes the shine move across the entire viewport width at a constant speed
3. Maintains the same visual effect but with consistent timing regardless of element size

The shine will now move at the same speed across any element, whether it's 100px wide or 1000px wide, because it's based on viewport width rather than element width.
